with seed(ord,teks_code,rit_band,difficulty,stem,stem_image_svg,explanation,source_note,choices) as (values
(1,$code$4.2B.vi$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word has three syllables?$stem$,NULL,$exp$Ad-ven-ture has three syllables. The other words have one syllable.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"adventure","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"plain","is_correct":false,"misconception":"Counted letters instead of spoken syllables.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"stream","is_correct":false,"misconception":"Counted letters instead of spoken syllables.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"bright","is_correct":false,"misconception":"Counted letters instead of spoken syllables.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(2,$code$4.2B.vi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which division shows the syllables in careful?$stem$,NULL,$exp$Careful divides into care-ful. Each part has a vowel sound.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"caref-ul","is_correct":false,"misconception":"Split the word without listening for vowel sounds.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"care-ful","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"ca-reful","is_correct":false,"misconception":"Split the word without listening for vowel sounds.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"car-eful","is_correct":false,"misconception":"Split the word without listening for vowel sounds.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(3,$code$4.2B.vi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word has a final stable syllable?$stem$,NULL,$exp$The -ble ending in table is a final stable syllable.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"trail","is_correct":false,"misconception":"Missed the final stable syllable pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"team","is_correct":false,"misconception":"Missed the final stable syllable pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"table","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"tape","is_correct":false,"misconception":"Missed the final stable syllable pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(4,$code$4.2B.vi$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which syllable type is the first syllable in robot?$stem$,NULL,$exp$Ro is open because it ends with a vowel sound.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"closed syllable","is_correct":false,"misconception":"Confused an open syllable with another syllable type.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"vowel team","is_correct":false,"misconception":"Confused an open syllable with another syllable type.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"r-controlled","is_correct":false,"misconception":"Confused an open syllable with another syllable type.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"open syllable","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(5,$code$4.2C.i$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word is spelled correctly?$stem$,NULL,$exp$Important is the correct spelling.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"important","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"importent","is_correct":false,"misconception":"Chose a spelling that leaves out or changes a syllable.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"imporant","is_correct":false,"misconception":"Chose a spelling that leaves out or changes a syllable.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"impartant","is_correct":false,"misconception":"Chose a spelling that leaves out or changes a syllable.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(6,$code$4.2C.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is spelled correctly?$stem$,NULL,$exp$Different is spelled with diff-er-ent.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"differnt","is_correct":false,"misconception":"Dropped a letter from a multisyllabic spelling pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"different","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"diffrent","is_correct":false,"misconception":"Dropped a letter from a multisyllabic spelling pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"diferent","is_correct":false,"misconception":"Dropped a letter from a multisyllabic spelling pattern.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(7,$code$4.2C.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is spelled correctly?$stem$,NULL,$exp$Favorite is the standard spelling.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"favorit","is_correct":false,"misconception":"Used a common pronunciation-based misspelling.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"faverite","is_correct":false,"misconception":"Used a common pronunciation-based misspelling.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"favorite","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"favrite","is_correct":false,"misconception":"Used a common pronunciation-based misspelling.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(8,$code$4.2C.i$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence has the correctly spelled word?$stem$,NULL,$exp$Museum, exhibit, and interesting are all spelled correctly.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The museam exhibit was interesting.","is_correct":false,"misconception":"Misspelled a multisyllabic word by sound.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"The museum exzibit was interesting.","is_correct":false,"misconception":"Misspelled a multisyllabic word by sound.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"The museum exhibit was intresting.","is_correct":false,"misconception":"Misspelled a multisyllabic word by sound.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"The museum exhibit was interesting.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(9,$code$4.2C.ii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word is formed correctly from hope + ful?$stem$,NULL,$exp$Hopeful keeps the e and adds -ful.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"hopeful","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"hopefull","is_correct":false,"misconception":"Applied the wrong suffix spelling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"hopful","is_correct":false,"misconception":"Applied the wrong suffix spelling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"hopeeful","is_correct":false,"misconception":"Applied the wrong suffix spelling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(10,$code$4.2C.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is formed correctly from happy + ness?$stem$,NULL,$exp$Change y to i before adding -ness: happiness.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"hapiness","is_correct":false,"misconception":"Forgot to change y to i before adding a suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"happiness","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"happyness","is_correct":false,"misconception":"Forgot to change y to i before adding a suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"happyiness","is_correct":false,"misconception":"Forgot to change y to i before adding a suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(11,$code$4.2C.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is formed correctly from stop + ing?$stem$,NULL,$exp$Double the final consonant before -ing: stopping.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"stoppping","is_correct":false,"misconception":"Forgot or overused the doubling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"stopening","is_correct":false,"misconception":"Forgot or overused the doubling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"stopping","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"stoping","is_correct":false,"misconception":"Forgot or overused the doubling rule.","misconception_tag":"spelling_pattern_confusion","sort_order":4}]$choices$::jsonb),
(12,$code$4.2C.ii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which word is formed correctly from create + ive?$stem$,NULL,$exp$Drop the final e before adding -ive: creative.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"createive","is_correct":false,"misconception":"Did not drop the final e before a vowel suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":1},{"label":"B","body":"creativ","is_correct":false,"misconception":"Did not drop the final e before a vowel suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":2},{"label":"C","body":"creatitive","is_correct":false,"misconception":"Did not drop the final e before a vowel suffix.","misconception_tag":"spelling_pattern_confusion","sort_order":3},{"label":"D","body":"creative","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(13,$code$4.2C.iii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the correct word: ___ going to the library.$stem$,NULL,$exp$They're means they are.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"They're","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"Their","is_correct":false,"misconception":"Confused homophones with the same sound.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"There","is_correct":false,"misconception":"Confused homophones with the same sound.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"Thair","is_correct":false,"misconception":"Confused homophones with the same sound.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(14,$code$4.2C.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct word: Maya put ___ backpack by the door.$stem$,NULL,$exp$Her shows whose backpack it is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"she","is_correct":false,"misconception":"Chose a sound-alike or wrong pronoun.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"her","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"hear","is_correct":false,"misconception":"Chose a sound-alike or wrong pronoun.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"here","is_correct":false,"misconception":"Chose a sound-alike or wrong pronoun.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(15,$code$4.2C.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct word: We have ___ tickets for the show.$stem$,NULL,$exp$Two names the number.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"too","is_correct":false,"misconception":"Confused to, too, and two.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"tow","is_correct":false,"misconception":"Confused to, too, and two.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"two","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"to","is_correct":false,"misconception":"Confused to, too, and two.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(16,$code$4.2C.iii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Choose the correct word: The team won ___ game yesterday.$stem$,NULL,$exp$Its shows possession. It's means it is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"it's","is_correct":false,"misconception":"Confused possessive its with the contraction it's.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"its'","is_correct":false,"misconception":"Confused possessive its with the contraction it's.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"it","is_correct":false,"misconception":"Confused possessive its with the contraction it's.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"its","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(17,$code$4.11D.i$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence is correct?$stem$,NULL,$exp$Plural dogs takes bark.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The dogs bark at the gate.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"The dogs barks at the gate.","is_correct":false,"misconception":"Matched the verb to the wrong number.","misconception_tag":"subject_verb_agreement","sort_order":2},{"label":"C","body":"The dog bark at the gate.","is_correct":false,"misconception":"Matched the verb to the wrong number.","misconception_tag":"subject_verb_agreement","sort_order":3},{"label":"D","body":"The dogs is bark at the gate.","is_correct":false,"misconception":"Matched the verb to the wrong number.","misconception_tag":"subject_verb_agreement","sort_order":4}]$choices$::jsonb),
(18,$code$4.11D.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses correct subject-verb agreement?$stem$,NULL,$exp$Each is singular, so use has.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Each student are a notebook.","is_correct":false,"misconception":"Treated each as plural.","misconception_tag":"subject_verb_agreement","sort_order":1},{"label":"B","body":"Each student has a notebook.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"Each student have a notebook.","is_correct":false,"misconception":"Treated each as plural.","misconception_tag":"subject_verb_agreement","sort_order":3},{"label":"D","body":"Each students has a notebook.","is_correct":false,"misconception":"Treated each as plural.","misconception_tag":"subject_verb_agreement","sort_order":4}]$choices$::jsonb),
(19,$code$4.11D.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence is correct?$stem$,NULL,$exp$Class is a collective noun used as one group, so use is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The class visit the museum yesterday.","is_correct":false,"misconception":"Treated a collective noun as plural.","misconception_tag":"subject_verb_agreement","sort_order":1},{"label":"B","body":"The class were visiting the museum.","is_correct":false,"misconception":"Treated a collective noun as plural.","misconception_tag":"subject_verb_agreement","sort_order":2},{"label":"C","body":"The class is visiting the museum.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"The class are visiting the museum.","is_correct":false,"misconception":"Treated a collective noun as plural.","misconception_tag":"subject_verb_agreement","sort_order":4}]$choices$::jsonb),
(20,$code$4.11D.i$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence is correct?$stem$,NULL,$exp$Neither is singular, so use is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Neither of the answers are correct.","is_correct":false,"misconception":"Matched the verb to answers instead of neither.","misconception_tag":"subject_verb_agreement","sort_order":1},{"label":"B","body":"Neither of the answers be correct.","is_correct":false,"misconception":"Matched the verb to answers instead of neither.","misconception_tag":"subject_verb_agreement","sort_order":2},{"label":"C","body":"Neither of the answers were correct.","is_correct":false,"misconception":"Matched the verb to answers instead of neither.","misconception_tag":"subject_verb_agreement","sort_order":3},{"label":"D","body":"Neither of the answers is correct.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb)
), ins as (
  insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format)
  select 'language'::map_subject,4,s.id,null,seed.rit_band,seed.difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq'
  from seed
  join map_standards s on s.grade=4 and s.subject='language'::map_subject and s.teks_code=seed.teks_code
  where not exists (
    select 1 from map_questions q
    where q.grade=4 and q.subject='language'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.explanation=seed.explanation
  )
  returning id, stem, explanation, source_note
)
insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order)
select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order
from ins
join seed on seed.stem=ins.stem and seed.explanation=ins.explanation and seed.source_note=ins.source_note
cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1), body text, is_correct boolean, misconception text, misconception_tag text, sort_order smallint);